def execute(params):
    """Read contents of a file with chunking support."""
    import os
    file_path = params.get('filePath')
    start_line = params.get('startLine')
    end_line = params.get('endLine')
    chunk_index = params.get('chunkIndex')
    chunk_size = params.get('chunkSize', 500)
    max_chars = 100000

    if not file_path:
        return {'success': False, 'error': 'filePath parameter is required'}

    try:
        with open(file_path, 'r') as f:
            lines = f.readlines()
        total_lines = len(lines)
        total_chars = sum(len(l) for l in lines)
        estimated_tokens = total_chars // 4

        # Line range mode
        if start_line is not None or end_line is not None:
            start = max(0, (start_line or 1) - 1)
            end = min(total_lines, end_line or total_lines)
            selected = lines[start:end]
            return {'success': True, 'filePath': file_path, 'content': ''.join(selected), 'lineRange': {'start': start+1, 'end': end}, 'totalLines': total_lines}

        # Chunk mode
        if chunk_index is not None:
            total_chunks = (total_lines + chunk_size - 1) // chunk_size
            if chunk_index < 0 or chunk_index >= total_chunks:
                return {'success': False, 'error': f'Invalid chunkIndex. Valid: 0-{total_chunks-1}'}
            start = chunk_index * chunk_size
            end = min(start + chunk_size, total_lines)
            chunk_lines = lines[start:end]
            return {'success': True, 'filePath': file_path, 'content': ''.join(chunk_lines), 'chunkInfo': {'currentChunk': chunk_index, 'totalChunks': total_chunks, 'lineRange': {'start': start+1, 'end': end}}, 'totalLines': total_lines}

        # Auto-chunk if too large
        if total_chars > max_chars:
            total_chunks = (total_lines + chunk_size - 1) // chunk_size
            preview = ''.join(lines[:50]) + ('\n... [truncated]' if total_lines > 50 else '')
            return {'success': True, 'filePath': file_path, 'warning': 'FILE_TOO_LARGE', 'message': f'File has {total_lines} lines (~{estimated_tokens} tokens). Use chunkIndex to read in parts.', 'preview': preview, 'fileInfo': {'totalLines': total_lines, 'totalChars': total_chars, 'totalChunks': total_chunks, 'chunkSize': chunk_size}}

        return {'success': True, 'content': ''.join(lines), 'filePath': file_path, 'totalLines': total_lines, 'totalChars': total_chars}
    except FileNotFoundError:
        return {'success': False, 'error': f'File not found: {file_path}'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

