def execute(params):
    import subprocess, os
    repo_path = params.get('repoPath') or os.getcwd()
    if not os.path.isdir(repo_path):
        return {'success': False, 'error': 'repoPath not a directory: ' + str(repo_path)}
    limit = int(params.get('limit') or 30)
    path = (params.get('path') or '').strip()
    ref = (params.get('ref') or '').strip()
    since = (params.get('since') or '').strip()
    until = (params.get('until') or '').strip()
    author = (params.get('author') or '').strip()
    grep = (params.get('grep') or '').strip()
    oneline = bool(params.get('oneline'))
    if path:
        if path.startswith('/'):
            rp = os.path.realpath(repo_path).rstrip('/')
            pp = os.path.realpath(path)
            if pp == rp:
                path = '.'
            elif pp.startswith(rp + '/'):
                path = pp[len(rp) + 1:]
            else:
                return {'success': False, 'error': 'path must be repo-relative (e.g. "src/app.py" or "."), not absolute: ' + path}

    if oneline:
        cmd = ['git', '-C', repo_path, 'log', '--oneline', '-' + str(limit)]
    else:
        cmd = ['git', '-C', repo_path, 'log',
               '--pretty=format:%H%x1f%an%x1f%ae%x1f%at%x1f%s%x1f%b%x1e',
               '-' + str(limit)]
    if since:
        cmd += ['--since', since]
    if until:
        cmd += ['--until', until]
    if author:
        cmd += ['--author', author]
    if grep:
        cmd += ['--grep', grep, '-i']
    if ref:
        cmd.append(ref)
    if path:
        cmd += ['--', path]
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=60)
    except Exception as e:
        return {'success': False, 'error': 'log failed: ' + str(e)}
    if r.returncode != 0:
        return {'success': False, 'error': 'git log: ' + (r.stderr or r.stdout)[:400]}

    commits = []
    if oneline:
        for line in r.stdout.splitlines():
            if not line:
                continue
            parts = line.split(' ', 1)
            commits.append({'sha': parts[0], 'subject': parts[1] if len(parts) > 1 else ''})
    else:
        # Records separated by \x1e (record sep); fields by \x1f.
        for record in r.stdout.split('\x1e'):
            record = record.strip('\n')
            if not record:
                continue
            parts = record.split('\x1f')
            if len(parts) < 5:
                continue
            try:
                ts = int(parts[3])
            except Exception:
                ts = None
            commits.append({
                'sha': parts[0][:10],
                'full_sha': parts[0],
                'author': parts[1],
                'email': parts[2],
                'unix': ts,
                'subject': parts[4],
                'body': parts[5].strip() if len(parts) > 5 else '',
            })
    return {
        'success': True,
        'repoPath': repo_path,
        'filters': {
            'path': path or None, 'ref': ref or None, 'since': since or None,
            'until': until or None, 'author': author or None, 'grep': grep or None,
            'limit': limit,
        },
        'count': len(commits),
        'commits': commits,
    }

