    if not tar_path:
        return {'success': False, 'error': 'tarPath parameter is required'}
    if not source_paths:
        return {'success': False, 'error': 'sourcePaths parameter is required'}

    mode = 'w'
    if compression:
        mode = f'w:{compression}'

    try:
        file_count = 0
        with tarfile.open(tar_path, mode) as tar:
            for source_path in source_paths:
                tar.add(source_path, arcname=os.path.basename(source_path))
                if os.path.isfile(source_path):
                    file_count += 1
                else:
                    for root, dirs, files in os.walk(source_path):
                        file_count += len(files)

        return {
            'success': True,
            'message': f'Created tar archive with {file_count} files',
            'tarPath': tar_path,
            'compression': compression or 'none',
            'fileCount': file_count
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Analyze a video file for metadata and optionally extract frames."""
    import subprocess
    import json
    import os

    video_path = params.get('videoPath')
    if not video_path:
        return {'success': False, 'error': 'videoPath parameter is required'}

    if not os.path.exists(video_path):
        return {'success': False, 'error': f'Video file not found: {video_path}'}

    extract_frames = params.get('extractFrames', False)
    frame_interval = params.get('frameInterval', 10)
    output_dir = params.get('outputDir', os.path.dirname(video_path) or '.')

    results = {
        'success': True,
        'videoPath': video_path,
        'metadata': {}
    }

    # Use ffprobe to get video metadata
    try:
        ffprobe_cmd = [
            'ffprobe',
            '-v', 'quiet',
            '-print_format', 'json',
            '-show_format',
            '-show_streams',
            video_path
        ]

        result = subprocess.run(ffprobe_cmd, capture_output=True, text=True, timeout=60)

        if result.returncode != 0:
            return {'success': False, 'error': f'ffprobe failed: {result.stderr}'}

        probe_data = json.loads(result.stdout)

        # Extract format info
        format_info = probe_data.get('format', {})
        results['metadata']['filename'] = os.path.basename(video_path)
        results['metadata']['format'] = format_info.get('format_long_name', 'Unknown')
        results['metadata']['duration'] = float(format_info.get('duration', 0))
        results['metadata']['duration_formatted'] = _format_duration(float(format_info.get('duration', 0)))
        results['metadata']['size_bytes'] = int(format_info.get('size', 0))
        results['metadata']['size_mb'] = round(int(format_info.get('size', 0)) / (1024 * 1024), 2)
        results['metadata']['bit_rate'] = int(format_info.get('bit_rate', 0))
        results['metadata']['bit_rate_mbps'] = round(int(format_info.get('bit_rate', 0)) / 1000000, 2)

        # Extract stream info
        streams = probe_data.get('streams', [])
        video_streams = [s for s in streams if s.get('codec_type') == 'video']
        audio_streams = [s for s in streams if s.get('codec_type') == 'audio']

        if video_streams:
            vs = video_streams[0]
            results['metadata']['video'] = {
                'codec': vs.get('codec_name', 'Unknown'),
                'codec_long': vs.get('codec_long_name', 'Unknown'),
                'width': vs.get('width', 0),
                'height': vs.get('height', 0),
                'resolution': f"{vs.get('width', 0)}x{vs.get('height', 0)}",
                'aspect_ratio': vs.get('display_aspect_ratio', 'Unknown'),
                'frame_rate': _parse_frame_rate(vs.get('r_frame_rate', '0/1')),
                'frame_count': int(vs.get('nb_frames', 0)) if vs.get('nb_frames') else 'Unknown',
                'pixel_format': vs.get('pix_fmt', 'Unknown'),
                'color_space': vs.get('color_space', 'Unknown'),
                'bit_depth': vs.get('bits_per_raw_sample', 'Unknown')
            }

        if audio_streams:
            aus = audio_streams[0]
            results['metadata']['audio'] = {
                'codec': aus.get('codec_name', 'Unknown'),
                'codec_long': aus.get('codec_long_name', 'Unknown'),
                'channels': aus.get('channels', 0),
                'channel_layout': aus.get('channel_layout', 'Unknown'),
                'sample_rate': int(aus.get('sample_rate', 0)),
                'bit_rate': int(aus.get('bit_rate', 0)) if aus.get('bit_rate') else 'Unknown'
            }

        results['metadata']['stream_count'] = {
            'video': len(video_streams),
            'audio': len(audio_streams),
            'total': len(streams)
        }

    except subprocess.TimeoutExpired:
        return {'success': False, 'error': 'ffprobe timed out'}
    except FileNotFoundError:
        return {'success': False, 'error': 'ffprobe not found. Please install ffmpeg.'}
    except json.JSONDecodeError as e:
        return {'success': False, 'error': f'Failed to parse ffprobe output: {str(e)}'}
    except Exception as e:
        return {'success': False, 'error': f'Error analyzing video: {str(e)}'}

    # Extract frames if requested
    if extract_frames:
        try:
            os.makedirs(output_dir, exist_ok=True)
            base_name = os.path.splitext(os.path.basename(video_path))[0]
            frame_pattern = os.path.join(output_dir, f'{base_name}_frame_%04d.jpg')

            # Calculate number of frames to extract
            duration = results['metadata'].get('duration', 0)
            if duration > 0:
                ffmpeg_cmd = [
                    'ffmpeg',
                    '-i', video_path,
                    '-vf', f'fps=1/{frame_interval}',
                    '-q:v', '2',
                    '-y',
                    frame_pattern
                ]

                result = subprocess.run(ffmpeg_cmd, capture_output=True, text=True, timeout=300)

                if result.returncode == 0:
                    # Count extracted frames
                    extracted = [f for f in os.listdir(output_dir) if f.startswith(f'{base_name}_frame_') and f.endswith('.jpg')]
                    results['frames'] = {
                        'extracted': True,
                        'count': len(extracted),
                        'interval_seconds': frame_interval,
                        'output_dir': output_dir,
                        'files': sorted(extracted)[:10]  # First 10 for reference
                    }
                else:
                    results['frames'] = {
                        'extracted': False,
                        'error': result.stderr[:500] if result.stderr else 'Unknown error'
                    }
            else:
                results['frames'] = {
                    'extracted': False,
                    'error': 'Could not determine video duration'
                }
        except Exception as e:
            results['frames'] = {
                'extracted': False,
                'error': str(e)
            }

    return results

def _format_duration(seconds):
    """Format seconds into HH:MM:SS.ms"""
    hours = int(seconds // 3600)
    minutes = int((seconds % 3600) // 60)
    secs = seconds % 60
    if hours > 0:
        return f'{hours}:{minutes:02d}:{secs:05.2f}'
    else:
        return f'{minutes}:{secs:05.2f}'

def _parse_frame_rate(rate_str):
    """Parse frame rate from fraction string like '30000/1001'"""
    try:
        if '/' in rate_str:
            num, den = map(int, rate_str.split('/'))
            return round(num / den, 2) if den != 0 else 0
        return float(rate_str)
    except:
        return 0

def execute(params):
    import ast
    import operator as op
    expr = params.get('expression') or params.get('expr') or ''
    if not isinstance(expr, str) or not expr.strip():
        return {'success': False, 'error': 'expression required'}
    if len(expr) > 500:
        return {'success': False, 'error': 'expression too long (max 500 chars)'}
    allowed_ops = {
        ast.Add: op.add, ast.Sub: op.sub, ast.Mult: op.mul, ast.Div: op.truediv,
        ast.FloorDiv: op.floordiv, ast.Mod: op.mod, ast.Pow: op.pow,
        ast.USub: op.neg, ast.UAdd: op.pos,
    }
    allowed_funcs = {
        'abs': abs, 'min': min, 'max': max, 'round': round,
        'sum': sum, 'len': len, 'int': int, 'float': float,
        'sqrt': lambda x: x ** 0.5, 'pow': pow,
    }
    try:
        node = ast.parse(expr, mode='eval').body
        def _ev(n):
            if isinstance(n, ast.Constant):
                return n.value
            if isinstance(n, ast.BinOp) and type(n.op) in allowed_ops:
                return allowed_ops[type(n.op)](_ev(n.left), _ev(n.right))
            if isinstance(n, ast.UnaryOp) and type(n.op) in allowed_ops:
                return allowed_ops[type(n.op)](_ev(n.operand))
            if isinstance(n, ast.Call) and isinstance(n.func, ast.Name) and n.func.id in allowed_funcs:
                return allowed_funcs[n.func.id](*[_ev(a) for a in n.args])
            if isinstance(n, ast.List):
                return [_ev(x) for x in n.elts]
            if isinstance(n, ast.Tuple):
                return tuple(_ev(x) for x in n.elts)
            raise ValueError('disallowed syntax: ' + type(n).__name__)
        result = _ev(node)
        return {'success': True, 'expression': expr, 'result': result}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    from datetime import datetime, timedelta
    op = (params.get('operation') or params.get('op') or '').lower()
    def _parse(s):
        if not s or not isinstance(s, str):
            return None
        s = s.strip()
        for fmt in ('%Y-%m-%d %H:%M:%S', '%Y-%m-%d %H:%M', '%Y-%m-%dT%H:%M:%S', '%Y-%m-%d', '%Y/%m/%d', '%m/%d/%Y', '%m/%d/%y', '%d %b %Y', '%B %d %Y', '%B %d, %Y'):
            try:
                return datetime.strptime(s, fmt)
            except ValueError:
                continue
        try:
            return datetime.fromisoformat(s.replace('Z', '+00:00'))
        except Exception:
            return None
    if op == 'now' or op == '':
        now = datetime.now()
        return {'success': True, 'now': now.isoformat(), 'iso_date': now.date().isoformat(), 'weekday': now.strftime('%A'), 'unix': int(now.timestamp())}
    a = _parse(params.get('date') or params.get('a') or params.get('start'))
    if op in ('add', 'subtract'):
        if not a:
            return {'success': False, 'error': 'date required'}
        days = int(params.get('days') or 0)
        weeks = int(params.get('weeks') or 0)
        hours = int(params.get('hours') or 0)
        minutes = int(params.get('minutes') or 0)
        delta = timedelta(days=days + 7 * weeks, hours=hours, minutes=minutes)
        if op == 'subtract':
            delta = -delta
        r = a + delta
        return {'success': True, 'result': r.isoformat(), 'weekday': r.strftime('%A')}
    if op == 'diff':
        b = _parse(params.get('b') or params.get('end') or params.get('to'))
        if not a or not b:
            return {'success': False, 'error': 'two dates required (date + b)'}
        d = b - a
        return {'success': True, 'days': d.days, 'seconds': int(d.total_seconds()), 'hours': round(d.total_seconds() / 3600, 2), 'human': str(d)}
    if op == 'weekday':
        if not a:
            return {'success': False, 'error': 'date required'}
        return {'success': True, 'date': a.date().isoformat(), 'weekday': a.strftime('%A'), 'iso_weekday': a.isoweekday()}
    if op == 'business_days':
        b = _parse(params.get('b') or params.get('end'))
        if not a or not b:
            return {'success': False, 'error': 'two dates required (date + b)'}
        if b < a:
            a, b = b, a
        bd = 0
        cur = a.date()
        end = b.date()
        while cur <= end:
            if cur.weekday() < 5:
                bd += 1
            cur = cur + timedelta(days=1)
        return {'success': True, 'business_days': bd, 'calendar_days': (end - a.date()).days + 1}
    if op == 'format':
        if not a:
            return {'success': False, 'error': 'date required'}
        fmt = params.get('format') or '%Y-%m-%d'
        return {'success': True, 'formatted': a.strftime(fmt)}
    return {'success': False, 'error': "unknown operation '" + op + "'. Use: now, add, subtract, diff, weekday, business_days, format"}

def execute(params):
    from datetime import datetime
    try:
        from zoneinfo import ZoneInfo
    except ImportError:
        return {'success': False, 'error': 'zoneinfo unavailable; Python 3.9+ required'}
    time_str = (params.get('time') or params.get('datetime') or '').strip()
    from_tz = params.get('from_tz') or params.get('from') or 'UTC'
    to_tz = params.get('to_tz') or params.get('to') or 'UTC'
    if not time_str:
        return {'success': False, 'error': 'time required (e.g. "2026-04-24 09:00" or "9am")'}
    parsed = None
    for fmt in ('%Y-%m-%d %H:%M:%S', '%Y-%m-%d %H:%M', '%Y-%m-%dT%H:%M:%S', '%Y-%m-%dT%H:%M', '%Y-%m-%d', '%H:%M:%S', '%H:%M', '%I:%M %p', '%I:%M%p', '%I%p', '%I %p'):
        try:
            parsed = datetime.strptime(time_str, fmt)
            break
        except ValueError:
            continue
    if not parsed:
        try:
            parsed = datetime.fromisoformat(time_str.replace('Z', '+00:00')).replace(tzinfo=None)
        except Exception:
            return {'success': False, 'error': "could not parse time '" + time_str + "'"}
    if parsed.year == 1900:
        today = datetime.now().date()
        parsed = parsed.replace(year=today.year, month=today.month, day=today.day)
    try:
        src = ZoneInfo(from_tz)
        dst = ZoneInfo(to_tz)
    except Exception as e:
        return {'success': False, 'error': 'unknown timezone: ' + str(e)}
    aware = parsed.replace(tzinfo=src)
    converted = aware.astimezone(dst)
    return {
        'success': True,
        'input': aware.isoformat(),
        'converted': converted.isoformat(),
        'from_tz': from_tz,
        'to_tz': to_tz,
        'human': converted.strftime('%Y-%m-%d %H:%M %Z'),
    }

def execute(params):
    text = params.get('text', '')
