def execute(params):
    import os
    file_path = params.get('file') or '/models/.modelserver/todos.md'
    if not os.path.exists(file_path):
        return {'success': True, 'open': [], 'done': [], 'total': 0, 'file': file_path, 'note': 'no todo file yet — add one with todo_add'}
    show = (params.get('show') or 'open').lower()
    filter_tag = params.get('tag')
    open_items = []
    done_items = []
    with open(file_path, 'r', encoding='utf-8') as f:
        for idx, line in enumerate(f, 1):
            stripped = line.rstrip('\n')
            body = stripped.strip()
            if body.startswith('- [ ]'):
                text = body[5:].strip()
                if filter_tag and ('#' + filter_tag) not in stripped:
                    continue
                open_items.append({'line_no': idx, 'text': text})
            elif body.startswith('- [x]') or body.startswith('- [X]'):
                text = body[5:].strip()
                if filter_tag and ('#' + filter_tag) not in stripped:
                    continue
                done_items.append({'line_no': idx, 'text': text})
    out = {'success': True, 'file': file_path, 'total': len(open_items) + len(done_items)}
    if show == 'done':
        out['done'] = done_items
    elif show == 'all':
        out['open'] = open_items
        out['done'] = done_items
    else:
        out['open'] = open_items
    return out

def execute(params):
    import os, re
    from datetime import datetime
    file_path = params.get('file') or '/models/.modelserver/todos.md'
    if not os.path.exists(file_path):
        return {'success': False, 'error': 'no todo file at ' + file_path}
    target = (params.get('task') or params.get('text') or '').strip()
    line_no = params.get('line_no') or params.get('line')
    if not target and not line_no:
        return {'success': False, 'error': 'task (text) or line_no required'}
    with open(file_path, 'r', encoding='utf-8') as f:
        lines = f.readlines()
    matched = -1
    if line_no:
        try:
            ln = int(line_no)
            if 1 <= ln <= len(lines):
                matched = ln - 1
        except Exception:
            return {'success': False, 'error': 'invalid line_no'}
    else:
        tl = target.lower()
        for i, ln in enumerate(lines):
            s = ln.strip()
            if (s.startswith('- [ ]')) and tl in ln.lower():
                matched = i
                break
    if matched < 0:
        return {'success': False, 'error': 'no matching open todo found'}
    old = lines[matched]
    done_stamp = datetime.now().strftime('%Y-%m-%d')
    new = re.sub(r'- \[ \]', '- [x]', old, count=1).rstrip('\n') + ' (done ' + done_stamp + ')\n'
    lines[matched] = new
    with open(file_path, 'w', encoding='utf-8') as f:
        f.writelines(lines)
    return {'success': True, 'completed': old.rstrip(), 'line_no': matched + 1}

def execute(params):
    import os, io
    path = params.get('path') or params.get('file')
    content = params.get('content')
    if not path and not content:
        return {'success': False, 'error': 'path or content required'}
    try:
        import pandas as pd
        if path:
            if not os.path.exists(path):
                return {'success': False, 'error': 'file not found: ' + path}
            ext = os.path.splitext(path)[1].lower()
            if ext in ('.xlsx', '.xls'):
                df = pd.read_excel(path)
            elif ext == '.parquet':
                df = pd.read_parquet(path)
            elif ext == '.json':
                df = pd.read_json(path)
            else:
                df = pd.read_csv(path)
        else:
            df = pd.read_csv(io.StringIO(content))
        numeric_desc = {}
        for col in df.select_dtypes(include='number').columns:
            s = df[col]
            numeric_desc[str(col)] = {
                'count': int(s.count()),
                'null_count': int(s.isna().sum()),
                'mean': float(s.mean()) if s.count() else None,
                'min': float(s.min()) if s.count() else None,
                'max': float(s.max()) if s.count() else None,
                'median': float(s.median()) if s.count() else None,
                'std': float(s.std()) if s.count() > 1 else None,
            }
        string_desc = {}
        for col in df.select_dtypes(include='object').columns:
            s = df[col].astype(str)
            uniq = int(s.nunique())
            top = s.value_counts().head(5).to_dict() if uniq else {}
            string_desc[str(col)] = {
                'count': int(s.count()),
                'null_count': int(df[col].isna().sum()),
                'unique': uniq,
                'top': {str(k): int(v) for k, v in top.items()},
            }
        return {
            'success': True,
            'rows': int(len(df)),
            'columns': [str(c) for c in df.columns],
            'dtypes': {str(c): str(t) for c, t in df.dtypes.items()},
            'numeric': numeric_desc,
            'text': string_desc,
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    import os
    query = params.get('query') or params.get('sql')
    path = params.get('path') or params.get('file')
    path2 = params.get('path2')
    if not query:
        return {'success': False, 'error': 'query required'}
    if not path:
        return {'success': False, 'error': 'path required'}
    if not os.path.exists(path):
        return {'success': False, 'error': 'file not found: ' + path}
    try:
        import duckdb
        con = duckdb.connect(':memory:')
        def register(p, name):
            # DuckDB's read_*_auto helpers don't accept bound parameters,
            # so we inline the path after escaping embedded single quotes.
            q = "'" + p.replace("'", "''") + "'"
            ext = os.path.splitext(p)[1].lower()
            if ext in ('.xlsx', '.xls'):
                import pandas as pd
                df = pd.read_excel(p)
                con.register(name, df)
            elif ext == '.parquet':
                con.execute("CREATE VIEW " + name + " AS SELECT * FROM read_parquet(" + q + ")")
            elif ext == '.json':
                con.execute("CREATE VIEW " + name + " AS SELECT * FROM read_json_auto(" + q + ")")
            else:
                con.execute("CREATE VIEW " + name + " AS SELECT * FROM read_csv_auto(" + q + ")")
        register(path, 'data')
        if path2 and os.path.exists(path2):
            register(path2, 'data2')
        rows = con.execute(query).fetchdf()
        limit = int(params.get('limit') or 100)
        truncated = False
        if len(rows) > limit:
            rows = rows.head(limit)
            truncated = True
        return {
            'success': True,
            'columns': [str(c) for c in rows.columns],
            'rows': rows.to_dict(orient='records'),
            'row_count': len(rows),
            'truncated': truncated,
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

